mapper.select:
		/* wms-inbound-order-dlvr-sql-oracle.xml - selectIbHdMap - 반품입고 헤더 정보 조회 */
		SELECT *
		  FROM TWORK_INFO_IB_HD
		 WHERE CTKEY = #{ctkey}
		   AND OWKEY = #{owkey}
           AND IBHDTYPECD = '50'
		   AND CUSTORDNO = #{custordno}
           AND EXTORDERKEY = #{claimno}

mapper.update:
/* wms-inbound-order-dlvr-sql-oracle.xml - updaetInboundReturnWblno - 반품 운송장내역 운송장번호 및 상태 저장 */
UPDATE TWORK_INFO_IBRET_WBLNO
   SET WBLNO = #{wblno}
	 , WBLPRGRSTATUSCD = #{wblprgrstatuscd}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND WBLNO = #{obWblno}

/* wms-inbound-order-dlvr-sql-oracle.xml - updateInboundReturnWblnoSbm - 반품운송장 접수내역 저장 */
UPDATE TWORK_INFO_IBRET_WBLNO_SBM
   SET WBLNO = #{wblno}
	 , RICUSTORDNO = #{ricustordno}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND CUSTORDNO = #{orgcustordno}
   AND WBLNO = #{obWblno}

mapper.insert:
/* wms-inbound-order-dlvr-sql-oracle.xml - insertInboundReturnWblnoSbm - 반품운송장 접수내역 등록 */
INSERT INTO TWORK_INFO_IBRET_WBLNO_SBM
(
	CTKEY
	, CLAIMNO
	, CUSTORDNO
	, DLVRYCORPCD
	, WBLNO
	, OBWBLNO
	, RICUSTORDNO
	, CONT
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
)
VALUES
(
	#{ctkey}
	, #{claimno}
	, #{custordno}
	, #{dlvrycorpcd}
	, #{wblno}
	, #{obwblno}
	, #{ricustordno}
	, #{cont}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
)
